5% 0.95238 1.85941 2.72325 3.54595 12.08532 12.46221', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00194', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列何者不是財務資訊之強化性品質特性？', '["可比性", "可驗證性", "時效性", "攸關性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00195', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列對於會計的角色之敘述，何者正確？①藉由財務報表以評估繼續持有或出售原有投資或債權', '["藉由財務報表以評估經理人的績效是指會計扮演著「評價」 的角色", "藉由財務報表以評估企業的價值是指會計扮演著「家管」的角色", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00196', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司8月31日銀行調節表編製前的資料如下：帳列銀行存款$270,000；在途存款$45,200；銀行 對帳單餘額$247,730；公司尚未入帳之銀行手續費$90；未兌現支票$33,770；公司尚未入帳之存款 不足退票$10,840；公司會計人員誤將某一筆存入金額$2,980記為$2,890。試根據前述資料，計算 8月31日正確之銀行存款餘額為：', '["$259,070", "$259,160", "$315,110", "$315,200"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00197', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年12月31日應收帳款餘額$600,000，X2年12月31日應收帳款餘額$400,000，X2年 進貨$1,100,000，進貨折扣$200,000，進貨折讓$100,000，銷貨$3,200,000，銷貨折扣$600,000，銷 貨折讓$200,000，則X2年甲公司以期初與期末應收帳款簡單平均數計算之應收帳款週轉率為何？', '["4.8", "4.4", "6.4", "5.9"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00198', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司倉庫於10月20日發生大火，導致存貨全部毀損，已知10月份期初存貨為$150,000，進貨 $450,000，進貨運費$50,000，銷貨收入$900,000，銷貨運費$80,000，估計毛利率為銷貨的40%。 若採毛利率法估計，則甲公司存貨損失金額是多少？', '["$60,000", "$108,000", "$110,000", "$158,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00199', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司採定期盤存制，X1年7月28日甲公司向乙公司進貨，目的地交貨，甲公司於計算進貨成 本時必不受下列何者影響？', '["進貨運費", "進貨折扣", "進貨退回", "進貨折讓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00200', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-111-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列有關金融資產之會計處理，正確者有幾項？①採權益法認列之投資，期末不必進行公允價', '["透過其他綜合損益按公允價衡量之投資，其期末公允價值變動應列為當期損益", "按 攤銷後成本衡量之投資，期末必須以攤銷後成本表達", "透過損益按公允價值衡量之投資，其交 易成本應列為當期費用", "一項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:10+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
